Bash(node -e "
const fs = require\('fs'\);
const data = JSON.parse\(fs.readFileSync\('JLPT_Vocab.json', 'utf-8'\)\);

const levels = {N5: null, N4: null, N3: null, N2: null, N1: null};
for \(let i = 0; i < data.length; i++\) {
    const item = data[i];
    if \(Array.isArray\(item\) && item.length >= 2\) {
        if \(item[0] === item[1] && item[0] in levels\) {
            levels[item[0]] = i;
        }
    }
}

console.log\('JLPT_Vocab.json Structure:'\);
console.log\('Total items:', data.length\);
console.log\('\\\\nLevel markers \(index positions\):'\);
for \(const level of ['N5', 'N4', 'N3', 'N2', 'N1']\) {
    console.log\('  ' + level + ':', levels[level]\);
}

// Calculate level counts
const levelOrder = ['N5', 'N4', 'N3', 'N2', 'N1'];
const levelCounts = {};
for \(let i = 0; i < levelOrder.length; i++\) {
    const level = levelOrder[i];
    const start = levels[level] !== null ? levels[level] + 1 : 0;
    const nextLevel = i + 1 < levelOrder.length ? levelOrder[i + 1] : null;
    const end = nextLevel && levels[nextLevel] !== null ? levels[nextLevel] : data.length;
    levelCounts[level] = end - start;
}

console.log\('\\\\nWord counts per level \(exclusive\):'\);
for \(const level of levelOrder\) {
    console.log\('  ' + level + ':', levelCounts[level]\);
}

console.log\('\\\\nCumulative word counts:'\);
let cumulative = 0;
for \(const level of levelOrder\) {
    cumulative += levelCounts[level];
    console.log\('  Through ' + level + ':', cumulative\);
}

// Sample some entries
console.log\('\\\\nSample entries from data:'\);
for \(let i = 0; i < 5; i++\) {
    console.log\('  [' + i + ']:', data[i]\);
}
")
